const body = $input.first().json;

const userName = body.data?.user_name || 'Artist';
const userEmail = body.data?.user_email;
const avgScore = body.data?.average_score || 0;
const recentScores = body.data?.recent_scores || [];
const areas = body.data?.struggling_areas || [];
const eventType = body.event_type || 'performance.low_detected';

if (!userEmail) {
  throw new Error('No user_email in event data');
}

// Build score context
let scoreContext = '';
if (eventType === 'quiz.failed') {
  const score = body.data?.score || 0;
  scoreContext = `\nQuiz score: ${score}%`;
} else if (avgScore > 0) {
  scoreContext = `\nRecent average score: ${avgScore.toFixed(1)}%`;
  if (recentScores.length > 0) {
    scoreContext += ` (last ${recentScores.length} attempts: ${recentScores.join(', ')})`;
  }
}

const areasStr = areas.length > 0
  ? `\n\nTopics to focus on:\n${areas.map(a => `  • ${a}`).join('\n')}`
  : '';

const emailSubject = `💪 Let's get you back on track, ${userName}!`;

const emailBody = `Hi ${userName},

We noticed you've been having a tough time with some recent content — and that's completely normal! Every artist faces challenges.${scoreContext}${areasStr}

Here are some tips to help:
  • Go back and review the fundamentals
  • Try breaking topics into smaller steps
  • Don't rush — take your time with each lesson
  • Reach out if you need hints!

You've got this. Return to Art Buddy and give it another shot:
https://art-buddy-frontend.onrender.com

We believe in you!
The Art Buddy Team`;

return [{
  json: {
    user_email: userEmail,
    user_name: userName,
    emailSubject,
    emailBody
  }
}];
